INSERT INTO public.country_resource_sections (country_code, city, section_key, title, content_json, sort_order)
VALUES
  ('NO', NULL, 'welcome', 'Welcome', '{"intro": "Norway values work-life balance, punctuality, and egalitarianism. Most business is conducted in English.", "cultural_tips": ["Punctuality is expected — arrive on time", "Informal but professional communication", "Public holidays: 17 May (Constitution Day), Christmas, Easter", "Winter: prepare for short days; summer: long daylight"], "work_culture": ["Typical hours: 37.5/week", "Flexible working common", "Lunch often 30 min"]}'::jsonb, 0),
  ('NO', NULL, 'admin_essentials', 'Administrative Essentials', '{"topics": [{"title": "Residence registration (Folkeregisteret)", "timeline": "Within 7 days", "link": "https://www.skatteetaten.no/en/person/national-registry/"}, {"title": "Tax card (Skatt kort)", "timeline": "1–2 weeks", "link": "https://www.skatteetaten.no/"}, {"title": "D-number or ID number", "timeline": "At registration", "link": null}, {"title": "Bank account (BankID required)", "timeline": "1–2 weeks", "link": null}, {"title": "Mobile & BankID", "timeline": "First week", "link": null}, {"title": "GP registration (fastlege)", "timeline": "First month", "link": "https://helsenorge.no/"}]}'::jsonb, 1),
  ('NO', NULL, 'housing', 'Housing', '{"overview": "Oslo has a tight rental market. Finn.no is the main platform. Expect deposit of 2–3 months.", "platforms": [{"title": "Finn.no", "url": "https://www.finn.no/bolig/", "description": "Main rental and sale portal"}, {"title": "Hyalite", "url": "https://hyalite.io/", "description": "Expat-focused rentals"}], "neighborhoods": ["Frogner", "Grünerløkka", "Sagene", "Bærum (family-friendly)"]}'::jsonb, 2),
  ('NO', NULL, 'schools', 'Schools & Childcare', '{"overview": "Public school is free. International schools charge tuition. Barnehage (kindergarten) has parental fees.", "school_types": ["Public (Barneskole)", "International", "Private"], "topics": [{"title": "International schools (Oslo)", "timeline": "Apply early", "link": null}, {"title": "Barnehage enrollment", "timeline": "Register before arrival", "link": "https://oslo.kommune.no/barn-og-utdanning/"}]}'::jsonb, 3),
  ('NO', NULL, 'healthcare', 'Healthcare', '{"overview": "Public healthcare is subsidized. Register with a GP (fastlege). EU health card covers emergencies.", "emergency": "113", "topics": [{"title": "Emergency", "timeline": "113", "link": null}, {"title": "Non-emergency", "timeline": "116 117", "link": null}]}'::jsonb, 4),
  ('NO', NULL, 'transport', 'Transportation', '{"overview": "Ruter runs Oslo public transport. Monthly pass ~700–900 NOK. Cycling is popular.", "platforms": [{"title": "Ruter", "url": "https://ruter.no/", "description": "Public transport"}, {"title": "VY", "url": "https://www.vy.no/", "description": "Trains"}]}'::jsonb, 5),
  ('NO', NULL, 'daily_life', 'Daily Life Essentials', '{"overview": "Most shops close early on weekends. Rema 1000, Kiwi, Meny for groceries.", "items": [{"title": "Food delivery", "description": "Foodora, Wolt"}, {"title": "Banking", "description": "DNB, Nordea, Sbanken"}, {"title": "Mobile", "description": "Telenor, Telia, ICE"}]}'::jsonb, 6),
  ('NO', NULL, 'community', 'Community & Social Integration', '{"overview": "Expat communities and professional networks.", "groups": [{"title": "Internations Oslo", "url": "https://www.internations.org/oslo-expats", "description": "Expat meetups"}, {"title": "Meetup Oslo", "url": "https://www.meetup.com/cities/no/oslo/", "description": "Events and groups"}]}'::jsonb, 7),
  ('NO', NULL, 'culture_leisure', 'Culture & Leisure', '{"overview": "Oslo has museums, festivals, and a vibrant cultural scene.", "items": [{"title": "Munch Museum", "description": "Art museum", "url": "https://www.munchmuseet.no/"}, {"title": "Opera House", "description": "Opera and ballet", "url": "https://operaen.no/"}]}'::jsonb, 8),
  ('NO', NULL, 'nature', 'Nature & Weekend Activities', '{"overview": "Nordmarka offers hiking, skiing. Easy access from Oslo. Family-friendly trails.", "items": [{"title": "Nordmarka", "description": "Forest and lakes, 30 min from city"}, {"title": "Vigeland Park", "description": "Sculpture park, free"}]}'::jsonb, 9),
  ('NO', NULL, 'cost_of_living', 'Cost of Living Snapshot', '{"items": [{"label": "Average rent (1-bed)", "value": "~15,000–20,000 NOK"}, {"label": "Monthly transport", "value": "~700–900 NOK"}, {"label": "Groceries (monthly)", "value": "~4,000–6,000 NOK"}, {"label": "Restaurant meal", "value": "~200–350 NOK"}]}'::jsonb, 10),
  ('NO', NULL, 'safety', 'Safety & Practical Tips', '{"emergency": "113", "tips": ["Emergency: 113 (police/ambulance)", "Keep emergency numbers in phone", "Winter: dress in layers, watch for ice"]}'::jsonb, 11),
  ('SG', NULL, 'welcome', 'Welcome', '{"intro": "Singapore is a multicultural hub with English as the main business language. Efficient, safe, and well-connected.", "cultural_tips": ["Punctuality is expected", "Remove shoes before entering homes", "Public holidays: Chinese New Year, Hari Raya, Deepavali, Christmas", "Humid year-round; dress light"], "work_culture": ["Typical hours: 9–6", "Formal initially", "Many multinationals"]}'::jsonb, 0),
  ('SG', NULL, 'admin_essentials', 'Administrative Essentials', '{"topics": [{"title": "Entry visa / IPA", "timeline": "Before arrival", "link": "https://www.ica.gov.sg/"}, {"title": "Employment Pass (MOM)", "timeline": "Employer sponsors", "link": "https://www.mom.gov.sg/passes-and-permits"}, {"title": "Singpass registration", "timeline": "After EP approval", "link": "https://www.singpass.gov.sg/"}, {"title": "Bank account", "timeline": "1–2 weeks", "link": null}, {"title": "Mobile (local SIM)", "timeline": "First week", "link": null}, {"title": "CPF (employer-managed)", "timeline": "Automatic with employment", "link": "https://www.cpf.gov.sg/"}]}'::jsonb, 1),
  ('SG', NULL, 'housing', 'Housing', '{"overview": "HDB and private condos. Property Guru and 99.co are main portals. Expect 1–2 months deposit.", "platforms": [{"title": "PropertyGuru", "url": "https://www.propertyguru.com.sg/", "description": "Rental and sale listings"}, {"title": "99.co", "url": "https://www.99.co/singapore", "description": "Property search"}], "neighborhoods": ["Orchard", "Marina Bay", "Tiong Bahru", "East Coast", "Holland Village"]}'::jsonb, 2),
  ('SG', NULL, 'schools', 'Schools & Childcare', '{"overview": "Public schools, international schools (GIS, SAS, UWC), and private options. Fees vary widely.", "school_types": ["Public", "International", "Private"], "topics": [{"title": "MOE school registration", "timeline": "Check MOE website", "link": "https://www.moe.gov.sg/"}, {"title": "International schools", "timeline": "Apply early, waitlists common", "link": null}]}'::jsonb, 3),
  ('SG', NULL, 'healthcare', 'Healthcare', '{"overview": "Efficient public and private hospitals. Register at a polyclinic or private GP.", "emergency": "995", "topics": [{"title": "Emergency", "timeline": "995", "link": null}, {"title": "Non-emergency", "timeline": "1777", "link": null}]}'::jsonb, 4),
  ('SG', NULL, 'transport', 'Transportation', '{"overview": "MRT and buses run by SBS Transit / SMRT. EZ-Link or bank cards for fares.", "platforms": [{"title": "SMRT / SBS Transit", "url": "https://www.smrt.com.sg/", "description": "Public transport"}, {"title": "Grab", "url": "https://www.grab.com/sg/", "description": "Rideshare and food"}]}'::jsonb, 5),
  ('SG', NULL, 'daily_life', 'Daily Life Essentials', '{"overview": "Hawker centres, supermarkets (NTUC, Cold Storage), and delivery apps.", "items": [{"title": "Food delivery", "description": "GrabFood, Deliveroo, Foodpanda"}, {"title": "Banking", "description": "DBS, OCBC, UOB"}, {"title": "Mobile", "description": "Singtel, StarHub, M1"}]}'::jsonb, 6),
  ('SG', NULL, 'community', 'Community & Social Integration', '{"overview": "Active expat community. Many professional and social groups.", "groups": [{"title": "Internations Singapore", "url": "https://www.internations.org/singapore-expats", "description": "Expat meetups"}, {"title": "Meetup Singapore", "url": "https://www.meetup.com/cities/sg/singapore/", "description": "Events and groups"}]}'::jsonb, 7),
  ('SG', NULL, 'culture_leisure', 'Culture & Leisure', '{"overview": "Gardens by the Bay, museums, Sentosa, and year-round events.", "items": [{"title": "Gardens by the Bay", "description": "Gardens and conservatories", "url": "https://www.gardensbythebay.com.sg/"}, {"title": "National Gallery", "description": "Southeast Asian art", "url": "https://www.nationalgallery.sg/"}]}'::jsonb, 8),
  ('SG', NULL, 'nature', 'Nature & Weekend Activities', '{"overview": "East Coast Park, MacRitchie Reservoir, Pulau Ubin. Hot and humid; bring water.", "items": [{"title": "East Coast Park", "description": "Beach, cycling, BBQ pits"}, {"title": "MacRitchie Reservoir", "description": "Hiking, treetop walk"}]}'::jsonb, 9),
