  ('US', NULL, 'welcome', 'Welcome', '{"intro": "The US varies greatly by region. Major cities are diverse, fast-paced, and English-speaking.", "cultural_tips": ["Punctuality varies by region", "Direct communication common", "Federal holidays: Thanksgiving, July 4th, etc.", "State laws differ; check your state"], "work_culture": ["Hours vary by industry", "At-will employment common", "Benefits through employer"]}'::jsonb, 0),
  ('US', NULL, 'admin_essentials', 'Administrative Essentials', '{"topics": [{"title": "Visa / work authorization", "timeline": "Before arrival", "link": "https://travel.state.gov/"}, {"title": "SSN (Social Security Number)", "timeline": "1–2 weeks after entry", "link": "https://www.ssa.gov/"}, {"title": "State ID / driver''s license", "timeline": "Varies by state", "link": null}, {"title": "Bank account", "timeline": "First week", "link": null}, {"title": "Mobile plan", "timeline": "First week", "link": null}, {"title": "Health insurance", "timeline": "Via employer or marketplace", "link": "https://www.healthcare.gov/"}]}'::jsonb, 1),
  ('US', NULL, 'housing', 'Housing', '{"overview": "Rental markets vary by city. Zillow, Apartments.com, and local brokers. Security deposit typically 1–2 months.", "platforms": [{"title": "Zillow", "url": "https://www.zillow.com/", "description": "Rentals and sales"}, {"title": "Apartments.com", "url": "https://www.apartments.com/", "description": "Rental listings"}], "neighborhoods": ["Varies by city"]}'::jsonb, 2),
